<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Produtos</title>

<style>
body{
    margin:0;
    font-family: Arial, sans-serif;
    background:#fff3f0;
}

header{
    background:#ff6b6b;
    color:white;
    text-align:center;
    padding:20px;
    font-size:24px;
    font-weight:bold;
}

.search{
    padding:15px;
    text-align:center;
}

.search input{
    width:80%;
    padding:10px;
    border-radius:8px;
    border:1px solid #ccc;
}


.filtros{
    display:flex;
    justify-content:center;
    gap:10px;
    flex-wrap:wrap;
    margin-bottom:10px;
}

.filtros button{
    background:#eee;
    border:none;
    padding:8px 15px;
    border-radius:20px;
    cursor:pointer;
}

.filtros button:hover{
    background:#ff6b6b;
    color:white;
}


.container{
    display:grid;
    grid-template-columns: repeat(auto-fit,minmax(220px,1fr));
    gap:20px;
    padding:20px;
}

.card{
    background:white;
    border-radius:15px;
    box-shadow:0 4px 10px rgba(0,0,0,0.1);
    overflow:hidden;
    text-align:center;
    transition:0.3s;
}

.card:hover{
    transform:scale(1.05);
}

.card img{
    width:100%;
    height:150px;
    object-fit:cover;
}

.card h3{
    margin:10px 0;
}

.card p{
    color:#555;
    font-size:14px;
    padding:0 10px;
}

.preco{
    font-size:18px;
    color:#e74c3c;
    font-weight:bold;
    margin:10px 0;
}

button{
    background:#ff6b6b;
    color:white;
    border:none;
    padding:10px;
    width:80%;
    margin-bottom:15px;
    border-radius:8px;
    cursor:pointer;
}

button:hover{
}
</style>
</head>

<body>

<header>🛍️ Nossos Produtos</header>

<div class="search">
    <input type="text" placeholder="Buscar produto...">
</div>

<div class="filtros">
    <button>Todos</button>
    <button>Chocolate</button>
    <button>Frutas</button>
    <button>Especiais</button>
</div>

<div class="container">

    <div class="card">
        <img src="data:image/jpeg;base64," alt="Chocolate">
        <h3>Bolo de Chocolate</h3>
        <p>Delicioso bolo com brigadeiro</p>
        <div class="preco">R$ 10,00</div>
        <button>Adicionar</button>
    </div>

    <div class="card">
        <img src="https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRb8jSpwUGyoewT180VXEMC13HtcAMQomQyIg&s" alt="Morango">
        <h3>Bolo de Morango</h3>
        <p>Com pedaços de morango natural</p>
        <div class="preco">R$ 12,00</div>
        <button>Adicionar</button>
    </div>

    <div class="card">
        <img src="data:image/jpeg;base64," alt="Ninho">
        <h3>Leite Ninho</h3>
        <p>Cremoso e muito pedido</p>
        <div class="preco">R$ 13,00</div>
        <button>Adicionar</button>
    </div>

    <div class="card">
        <img src="https://encrypted-tbn2.gstatic.com/shopping?q=tbn:ANd9GcQY10L3JuUs-sGrcEcmtadbiNHnR4vYPesyLJQ34xLKJYw7gylJVMoGRhYGM-J-m55KXSqf3GbRGF2esNb9skbtTkJO9jWsg93vdxYLYTGD" alt="Oreo">
        <h3>Oreo</h3>
        <p>Com pedaços crocantes de Oreo</p>
        <div class="preco">R$ 14,00</div>
        <button>Adicionar</button>
    </div>

</div>

</body>
</html>